  '{"case_meta":{"title":"Post-operative Wound Dehiscence"},"patient":{"name":"Amr Khalil","age":58,"gender":"Male","avatar_type":"adult_male","occupation":"School teacher","background":"Known diabetic on oral hypoglycaemics. Had an elective open cholecystectomy 7 days ago."},"professional_attitude":{"max_score":10,"items":[{"key":"introduction","label":"Introduced themselves to the patient"},{"key":"clear_language","label":"Used clear, non-technical language"},{"key":"hand_hygiene","label":"Performed hand hygiene before examination"},{"key":"active_listening","label":"Demonstrated active listening"},{"key":"closure","label":"Explained plan and next steps to patient"}],"scoring_note":"Scored holistically from the full case interaction at submission."},"history_taking":{"mode":"paramedic_handover","max_score":8,"atmist_handover":{"age_time":"58-year-old male. Incident noted this morning at 07:30.","mechanism":"Post-operative day 7 following elective open cholecystectomy. Patient noticed serosanguinous discharge from midline abdominal wound.","injuries":"Midline abdominal wound with partial separation of skin and subcutaneous layers. No evisceration noted.","signs":"HR 96 bpm, BP 138/88 mmHg, Temp 38.1C, RR 18/min. Wound site: visible gap approximately 4 cm.","treatment":"Wound covered with sterile saline-soaked dressing. IV access established, 500 mL NS running. NBM."},"checklist":[{"key":"personal_history","label":"Personal History","items":[{"key":"age_occupation","label":"Age and occupation noted"},{"key":"diabetes","label":"Diabetes mellitus confirmed and duration noted"},{"key":"medications","label":"Current medications including oral hypoglycaemics"}]},{"key":"chief_complaint","label":"Chief Complaint","items":[{"key":"wound_opening","label":"Wound opening — onset and timing after surgery"},{"key":"discharge","label":"Nature of wound discharge (serosanguinous)"}]},{"key":"present_history","label":"Present History","items":[{"key":"cough_sneeze","label":"Increased intra-abdominal pressure events"},{"key":"fever","label":"Fever or signs of infection"},{"key":"pain","label":"Pain at wound site"},{"key":"bowel_function","label":"Bowel function post-operatively"}]},{"key":"past_medical_history","label":"Past Medical / Surgical History","items":[{"key":"prior_surgery","label":"Details of the original operation"},{"key":"steroids_chemo","label":"Steroid or immunosuppressive drug use"},{"key":"nutritional_state","label":"Nutritional state"}]},{"key":"family_history","label":"Family History","items":[{"key":"fh_diabetes","label":"Family history of diabetes"}]}],"comprehension_questions":[{"id":"hq1","question":"On which post-operative day did the wound dehiscence occur?","correct_answer":"Day 7","points":2},{"id":"hq2","question":"What was the nature of the wound discharge?","correct_answer":"Serosanguinous","points":2},{"id":"hq3","question":"What significant pre-existing condition impairs wound healing?","correct_answer":"Diabetes mellitus","points":2},{"id":"hq4","question":"What was the patient temperature on arrival?","correct_answer":"38.1C","points":2}]},"physical_examination":{"max_score":0,"note":"Reveal only — not scored.","regions":{"general":{"label":"General Appearance","finding":"Anxious, middle-aged male. Haemodynamically stable. BMI ~29."},"vital_signs":{"label":"Vital Signs","finding":"HR 96, BP 138/88, Temp 38.1C, RR 18, SpO2 98%."},"abdomen_inspection":{"label":"Abdomen — Inspection","finding":"Midline incision 12 cm. Lower third has visible 4 cm gap. Oedematous, erythematous edges. Serosanguinous discharge. No evisceration."},"abdomen_palpation":{"label":"Abdomen — Palpation","finding":"Mild tenderness at wound margins. Fascial layer appears intact. No peritoneal signs."},"wound_assessment":{"label":"Wound — Detailed Assessment","finding":"Superficial dehiscence. Deep fascia intact. No necrotic tissue. Early granulation tissue."},"lower_limbs":{"label":"Lower Limbs","finding":"No oedema. Pulses palpable. No DVT signs."}}},"investigations_labs":{"max_score":5,"key_tests":["CBC","Random Blood Glucose","HbA1c","Serum Albumin","CRP","Wound Swab Culture"],"available_tests":{"CBC":{"label":"Complete Blood Count","result":"WBC 13.2 (elevated), Hb 10.8 (mild anaemia), Plt 310","interpretation":"Leukocytosis consistent with wound infection.","is_key":true,"points":1},"Random Blood Glucose":{"label":"Random Blood Glucose","result":"16.4 mmol/L — significantly elevated","interpretation":"Poorly controlled diabetes.","is_key":true,"points":1},"HbA1c":{"label":"HbA1c","result":"9.2% — poor long-term control","interpretation":"Confirms chronic poor diabetes control.","is_key":true,"points":1},"Serum Albumin":{"label":"Serum Albumin","result":"26 g/L (low)","interpretation":"Protein deficiency impairs collagen synthesis.","is_key":true,"points":1},"CRP":{"label":"CRP","result":"68 mg/L (elevated)","interpretation":"Elevated inflammatory marker.","is_key":true,"points":0.5},"Wound Swab Culture":{"label":"Wound Swab Culture","result":"Pending. Gram stain: Gram-positive cocci.","interpretation":"Essential for antibiotic guidance.","is_key":true,"points":0.5},"Coagulation Profile":{"label":"Coagulation Profile","result":"PT 13.2, INR 1.1 — normal","interpretation":"Normal. Not contributing.","is_key":false,"points":0},"LFTs":{"label":"Liver Function Tests","result":"ALT 52 (mildly elevated). Bilirubin normal.","interpretation":"Not contributing to dehiscence.","is_key":false,"points":0},"Urea and Creatinine":{"label":"Urea and Creatinine","result":"Urea 7.8, Creatinine 98 — mildly elevated","interpretation":"Mild elevation, related to diabetes.","is_key":false,"points":0}}},"investigations_imaging":{"max_score":3,"key_investigations":["Wound Ultrasound"],"available_imaging":{"Wound Ultrasound":{"label":"Ultrasound of Wound","result":"Superficial fluid collection 3x2 cm. Fascial layer intact.","interpretation":"Confirms superficial dehiscence. No burst abdomen.","is_key":true,"points":2},"Erect Chest X-ray":{"label":"Erect Chest X-ray","result":"No free air. Lung fields clear.","interpretation":"Rules out pneumoperitoneum.","is_key":false,"points":1},"CT Abdomen":{"label":"CT Abdomen with Contrast","result":"Not indicated as first-line.","interpretation":"Would be indicated if burst abdomen suspected.","is_key":false,"points":0}}},"diagnosis":{"max_score":12,"rubric":{"possible_diagnosis":{"label":"List possible diagnoses","expected":["Superficial wound dehiscence","Wound infection","Burst abdomen (to exclude)","Wound haematoma"],"points":3,"model_answer":"Superficial wound dehiscence, SSI, burst abdomen to exclude."},"differential_diagnosis":{"label":"Rank differentials with reasoning","expected_top":"Superficial wound dehiscence secondary to SSI in poorly controlled diabetic","reasoning_points":["Diabetes delays healing","Hypoalbuminaemia","Wound infection","Day 7 timing","Fascial layer intact"],"points":4,"model_answer":"Superficial wound dehiscence secondary to SSI, on background of DM and hypoalbuminaemia."},"final_diagnosis":{"label":"State your final diagnosis","expected":"Superficial wound dehiscence secondary to SSI with impaired healing due to DM and hypoalbuminaemia.","points":5,"model_answer":"Superficial wound dehiscence of midline incision, secondary to SSI. Contributing: DM, hypoalbuminaemia, infection. Fascial layer intact."}}},"medical_management":{"max_score":8,"questions":[{"id":"mm1","type":"mcq","question":"Most important systemic factor to address?","options":["A. Start physiotherapy","B. Optimise blood glucose control","C. Prescribe Vitamin C only","D. Apply compression bandage"],"correct":"B","explanation":"Diabetes is primary systemic factor.","points":2},{"id":"mm2","type":"mcq","question":"Most appropriate antibiotic approach?","options":["A. No antibiotics","B. Empirical broad-spectrum antibiotics","C. Antifungal therapy","D. Oral antibiotics only"],"correct":"B","explanation":"Empirical IV antibiotics covering skin flora.","points":2},{"id":"mm3","type":"mcq","question":"Management for albumin 26 g/L?","options":["A. No action needed","B. Nutritional support — high protein diet","C. IV albumin only","D. Restrict protein"],"correct":"B","explanation":"Protein deficiency impairs collagen synthesis.","points":2},{"id":"mm4","type":"mcq","question":"Role of Vitamin C?","options":["A. No role","B. Required for protocollagen maturation","C. Causes excess collagen","D. Only relevant in burns"],"correct":"B","explanation":"Required for protocollagen maturation.","points":2}]},"surgical_management":{"max_score":14,"questions":[{"id":"sm1","type":"mcq","question":"Correct surgical approach with intact fascia?","options":["A. Immediate re-suture","B. Leave open, plan delayed primary closure","C. Skin grafting","D. Tight pressure dressing"],"correct":"B","explanation":"Contaminated wounds left open.","points":3},{"id":"sm2","type":"mcq","question":"Type of wound healing?","options":["A. Primary intention","B. Secondary intention","C. Tertiary intention","D. Will not heal"],"correct":"C","explanation":"Tertiary intention healing.","points":3},{"id":"sm3","type":"mcq","question":"Most appropriate dressing?","options":["A. Occlusive gauze","B. Moist wound dressing","C. Dry gauze only","D. No dressing"],"correct":"B","explanation":"Moist healing enhances process.","points":2},{"id":"sm4","type":"free_text","question":"Describe wound management steps in theatre.","points":6,"rubric":{"expected_points":["Saline irrigation","Remove necrotic tissue","Antiseptic sterilisation","Confirm fascial integrity","Debride wound edges","Leave wound open","Apply moist dressing","Re-examine Day 5"],"model_answer":"Saline irrigation, remove necrotic tissue, sterilise, confirm fascia, debride, leave OPEN, moist dressing, review Day 5.","points":6}}]},"monitoring_followup":{"max_score":6,"question":"Write monitoring and follow-up plan for next 7 days.","rubric":{"expected_points":["Daily wound inspection","Blood glucose 4x daily","Daily temperature and WBC","Repeat albumin Day 5","Review wound swab culture","Assess wound Day 5-7","Physiotherapy","Diabetes team review"],"model_answer":"Daily wound inspection, 4x CBG, daily vitals, culture follow-up, repeat albumin Day 5, nutritional support, Day 5-7 assess closure, diabetes team referral.","points":6}},"patient_family_advice":{"max_score":6,"question":"Write discharge advice for Mr Amr Khalil.","rubric":{"expected_points":["Wound care","Signs of re-infection","Diabetes management","High protein diet","Activity restrictions 6 weeks","Suture removal","Avoid smoking","Follow-up 1 week and 6 weeks"],"model_answer":"Wound care, warning signs, strict glucose control, high-protein diet, no heavy lifting 6 weeks, outpatient review 1 and 6 weeks.","points":6}},"conclusion":{"max_score":14,"tasks":[{"id":"c1","type":"ward_round_presentation","label":"Ward Round Presentation","instruction":"Present this case on a surgical ward round.","rubric":{"expected_structure":["Patient identifier","Presenting complaint","Key findings","Investigations","Diagnosis","Management","Plan"],"model_answer":"Mr Amr Khalil 58M POD7, wound dehiscence 4cm, T2DM poorly controlled, fascial intact, glucose 16.4 albumin 26 WBC 13.2, Dx superficial wound dehiscence 2ry SSI, wound open IV abx glucose optimisation, plan DPC Day 5-7.","points":6}},{"id":"c2","type":"key_decision","label":"Key Decision Analysis","instruction":"Single most important decision and consequences?","rubric":{"expected_answer":"Whether to re-close or leave open.","model_answer":"Re-closing infected wound traps infection, risks burst abdomen. Must leave open.","points":4}},{"id":"c3","type":"learning_point","label":"Reflection","instruction":"Name three factors impairing wound healing with mechanisms.","rubric":{"expected_points":["Diabetes — impairs leucocytes","Hypoalbuminaemia — diminished collagen","Infection — bacteria compete with fibroblasts"],"model_answer":"DM impairs leucocytes/microangiopathy, protein deficiency reduces collagen, infection destroys collagen fibres.","points":4}}]},"score_summary":{"sections":[{"section":"Professional Attitude","max_score":10},{"section":"History Taking","max_score":8},{"section":"Physical Examination","max_score":0},{"section":"Investigations — Labs","max_score":5},{"section":"Investigations — Imaging","max_score":3},{"section":"Diagnosis","max_score":12},{"section":"Medical Management","max_score":8},{"section":"Surgical Management","max_score":14},{"section":"Monitoring & Follow-up","max_score":6},{"section":"Patient & Family Advice","max_score":6},{"section":"Conclusion","max_score":14}],"total_max_score":86,"grade_bands":{"distinction":80,"pass":60,"borderline":50,"fail":0}}}'::jsonb
